func (e *executableSchema) Exec(ctx context.Context) graphql.ResponseHandler {
	opCtx := graphql.GetOperationContext(ctx)
	ec := newExecutionContext(opCtx, e, make(chan graphql.DeferredResult))
	inputUnmarshalMap := graphql.BuildUnmarshalerMap(
		ec.unmarshalInputAppendPromptInput,
		ec.unmarshalInputApprovalConfigInput,
		ec.unmarshalInputBranchDiffInput,
		ec.unmarshalInputBrowseDirectoryInput,
		ec.unmarshalInputCloseSessionInput,
		ec.unmarshalInputCreateProjectInput,
		ec.unmarshalInputCreateQuickCommandInput,
		ec.unmarshalInputCreateSessionInput,
		ec.unmarshalInputListQuickCommandsInput,
		ec.unmarshalInputListSessionFilesInput,
		ec.unmarshalInputListSessionsInput,
		ec.unmarshalInputListTranscriptEventsInput,
		ec.unmarshalInputMergeConfigInput,
		ec.unmarshalInputQuestionAnswerInput,
		ec.unmarshalInputRetryConfigInput,
		ec.unmarshalInputSaveWorkflowDefinitionInput,
		ec.unmarshalInputSessionCommitHistoryInput,
		ec.unmarshalInputSessionConfigInput,
		ec.unmarshalInputSessionDiffInput,
		ec.unmarshalInputSetDefaultWorkflowInput,
		ec.unmarshalInputSetSessionPriorityInput,
		ec.unmarshalInputSubmitQuestionBatchInput,
		ec.unmarshalInputSubmitWorkflowApprovalInput,
		ec.unmarshalInputUpdateProjectSettingsInput,
		ec.unmarshalInputUpdatePromptAppendInput,
		ec.unmarshalInputUpdateSessionConfigInput,
		ec.unmarshalInputWorkflowConditionInput,
		ec.unmarshalInputWorkflowEdgeInput,
		ec.unmarshalInputWorkflowGraphInput,
		ec.unmarshalInputWorkflowNodeInput,
		ec.unmarshalInputWorkflowNodePositionInput,
		ec.unmarshalInputWorkflowOutputFieldInput,
	)
	first := true

	switch opCtx.Operation.Operation {
	case ast.Query:
		return func(ctx context.Context) *graphql.Response {
			var response graphql.Response
			var data graphql.Marshaler
			if first {
				first = false
				ctx = graphql.WithUnmarshalerMap(ctx, inputUnmarshalMap)
				data = ec._Query(ctx, opCtx.Operation.SelectionSet)
			} else {
				if atomic.LoadInt32(&ec.PendingDeferred) > 0 {
					result := <-ec.DeferredResults
					atomic.AddInt32(&ec.PendingDeferred, -1)
					data = result.Result
					response.Path = result.Path
					response.Label = result.Label
					response.Errors = result.Errors
				} else {
					return nil
				}
			}
			var buf bytes.Buffer
			data.MarshalGQL(&buf)
			response.Data = buf.Bytes()
			if atomic.LoadInt32(&ec.Deferred) > 0 {
				hasNext := atomic.LoadInt32(&ec.PendingDeferred) > 0
				response.HasNext = &hasNext
			}

			return &response
		}
	case ast.Mutation:
		return func(ctx context.Context) *graphql.Response {
			if !first {
				return nil
			}
			first = false
			ctx = graphql.WithUnmarshalerMap(ctx, inputUnmarshalMap)
			data := ec._Mutation(ctx, opCtx.Operation.SelectionSet)
			var buf bytes.Buffer
			data.MarshalGQL(&buf)

			return &graphql.Response{
				Data: buf.Bytes(),
			}
		}
	case ast.Subscription:
		next := ec._Subscription(ctx, opCtx.Operation.SelectionSet)

		var buf bytes.Buffer
		return func(ctx context.Context) *graphql.Response {
			buf.Reset()
			data := next(ctx)

			if data == nil {
				return nil
			}
			data.MarshalGQL(&buf)

			return &graphql.Response{
				Data: buf.Bytes(),
			}
		}

	default:
		return graphql.OneShot(graphql.ErrorResponse(ctx, "unsupported GraphQL operation"))
	}
}

type executionContext struct {
	*graphql.ExecutionContextState[ResolverRoot, DirectiveRoot, ComplexityRoot]
}

func newExecutionContext(
	opCtx *graphql.OperationContext,
	execSchema *executableSchema,
	deferredResults chan graphql.DeferredResult,
) executionContext {
	return executionContext{
		ExecutionContextState: graphql.NewExecutionContextState[ResolverRoot, DirectiveRoot, ComplexityRoot](
			opCtx,
			(*graphql.ExecutableSchemaState[ResolverRoot, DirectiveRoot, ComplexityRoot])(execSchema),
			parsedSchema,
			deferredResults,
		),
	}
}

